    if(bit)s|=(1<<pos);

    else s&=~(1<<pos);

}



class Sit{

public:

    int cost;

    int pos;

    int mask;

    Sit(int cost_,int pos_,int mask_){

        cost=cost_;

        pos=pos_;

        mask=mask_;

    }

    bool operator<(const Sit &s)const {

        return s.cost<this->cost;

    }

};



int d[16][1<<16];

priority_queue<Sit> que;

int bfs(){

    for(int j=0;j<n;j++)for(int k=0;k<(1<<n);k++)d[j][k]=INF;

    for(int i=0;i<n;i++){

        d[i][s]=0;

        que.push(Sit(0,i,s));

    }

    while(!que.empty()){

        Sit s=que.top();que.pop();

        if(d[s.pos][s.mask]<s.cost)continue;

        for(int i=0;i<n;i++){

            for(int j=0;j<n;j++){

                // ·ÅÉèÏÝ

